"""
MKT Original Language Commentary — Ezra chapters 4–7
Run: python3 scripts/zc-original-ezra-4-7.py

Language note: Ezra contains two large Aramaic sections — 4:8–6:18 and 7:12–26.
The surrounding narrative is Hebrew. Commentary on Aramaic verses notes the Aramaic
root forms rather than Hebrew; both belong to the Northwest Semitic family and share
many roots but differ in morphology, vocabulary, and syntactic conventions.
Ezra's scribal trilingualism (Hebrew, Aramaic, Persian-loanword) is itself a historical
witness to the Achaemenid administrative context.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZRA = {
  "4": {
    "1": "<p><strong>ṣārê yəhûḏāh ûbinyāmîn</strong> — 'adversaries of Judah and Benjamin.' The noun <em>ṣar</em> (H6862) means adversary, foe, oppressor; it is a common noun here, not a proper name. The same root underlies <em>ṣārāh</em> (distress) and stands opposite <em>šālôm</em>. The adversaries 'heard' (šāmaʿū) — the verb carries narrative weight throughout Ezra-Nehemiah; opposition is consistently triggered by news of building (cf. Neh 2:10; 4:1).</p>",
    "2": "<p><strong>nidroš</strong> — 'we worship' (Aramaic form of <em>dāraš</em>, H1875, lit. 'seek'). The claim is theologically loaded: to 'seek' God is covenant faithfulness language (cf. 2 Chr 14:4; 15:2). Their claim of shared worship is challenged by the context (2 Kgs 17:24–41 describes syncretic practice among the transplanted peoples of Samaria). The phrase 'just as you do' (<em>kākem</em>) asserts equivalence the returning community rejects.</p>",
    "3": "<p><strong>ên-lākem wālānû</strong> — 'you have no portion (<em>ḥēleq</em>) with us.' <em>ḥēleq</em> (H2506) is covenant-allocation language — the same word used for tribal land allotments (Josh 18:5) and for Israel's share in YHWH (Ps 16:5). Building the temple is a covenantal act belonging to those who stand in the covenant. Zerubbabel's refusal is not ethnic exclusion but a theological boundary: the mandate came from Cyrus to 'the people of Israel' specifically (1:3).</p>",
    "4": "<p><strong>mərapîm yəḏê ʿam-yəhûḏāh</strong> — 'weakening the hands of the people of Judah.' The hiphil participle of <em>rāpāh</em> (H7503) governs the sentence: lit. 'causing the hands to be slack.' 'Weak hands' is a Hebrew idiom for discouragement and inability to act (Isa 13:7; Jer 38:4; Ezek 7:17; Neh 6:9). The idiom recurs in Neh 6:9 when Nehemiah's enemies try the same tactic. <strong>ûmévahălîm ôtām</strong> — hiphil of <em>bāhal</em> (H926): 'unsettling, alarming them' — the pairing of external discouragement and internal alarm is the two-pronged opposition strategy throughout the book.</p>",
    "5": "<p><strong>yōʿăṣîm</strong> — 'counselors, advisors' (H3289 yāʿaṣ, qal ptcp). Hired consultants to frustrate (<em>pārar</em>, H6565, 'break, frustrate') the Judahites' plans in the courts of Cyrus and Darius. The funding of legal interference (Aramaic ‎<em>apar</em> in the later letters) is the escalation from discouragement (v4) to institutional opposition.</p>",
    "6": "<p>This verse marks a temporal jump to the reign of Ahasuerus (Xerxes, 486–465 BCE), decades after Cyrus. The Chronicler (author of Ezra) uses this anachronistic grouping to show the <em>pattern</em> of opposition across multiple Persian reigns rather than strict chronological sequence. The accusation is a <em>śiṭnāh</em> (H7855) — formal complaint; the word is cognate with <em>śāṭan</em> (accuser) and evokes the legal-accusatory role. Opposition to the covenant community takes the shape of legal slander before the king.</p>",
    "7": "<p>Last Hebrew verse before the Aramaic block begins. Three names (Bishlam, Mithredath, Tabeel) write to Artaxerxes. <strong>biktāb ʾărāmît</strong> — 'in Aramaic script (<em>kətāb</em>) and translated into Aramaic (<em>məturgam ʾărāmît</em>).' The phrase signals the transition: the next section (4:8–6:18) is written <em>in Aramaic</em> and preserves actual imperial correspondence in the chancellery language of the Persian court. This is a remarkable feature of the Hebrew canon — nearly two chapters of Scripture are composed in Aramaic, not Hebrew.</p>",
    "8": "<p><strong>Aramaic begins here (4:8–6:18).</strong> Rehum <em>baʿēl ṭəʿēm</em> — 'Rehum the commander' (lit. 'master of decree/report'; H2942 ṭəʿēm = taste/judgment/report, an Aramaic official title). Shimshai is <em>sāpərāʾ</em> — the scribe (Aramaic form of Hebrew <em>sōpēr</em>). These two frame the letter as a legal document with proper credentialing. The letter is composed (<em>kātab</em>) as official imperial correspondence — the Aramaic verb and vocabulary throughout mark it as authentic chancellery style.</p>",
    "9": "<p>The enumeration of peoples in the greeting formula follows Aramaic epistolary convention. <strong>dināyēʾ, ʾăpārsātəkāyēʾ</strong> etc. — various ethnic groups settled in Samaria by Osnappar (= Ashurbanipal, Assyrian king, 668–627 BCE). The list witnesses to the Assyrian deportation and resettlement policy (2 Kgs 17:24). The ethnic diversity of the signatories strengthens the legal claim by multiplying the number of aggrieved parties.</p>",
    "10": "<p><strong>ʾOsnapper</strong> (Ashurbanipal) is identified as 'great and noble' (<em>rab wəyaqqîr</em>) — the letter uses imperial honorifics for the previous Assyrian king even within a petition to the Persian king, flattering the tradition of powerful empire. <strong>Trans-Euphrates</strong> (<em>ʿăḇar naharāh</em>, lit. 'beyond the river') is the standard Persian administrative designation for the western satrapy including Syria-Palestine.</p>",
    "11": "<p>The letter's formal heading: <strong>ʿaḇdāk</strong> — 'your servants' — the standard submissive epistolary opener. The phrase 'men of Trans-Euphrates' frames the letter as coming from loyal subjects reporting a threat to the king's interests. Aramaic administrative letters from Elephantine (5th century BCE) follow the same 'your servants' convention, corroborating the authentic epistolary style of this section.</p>",
    "12": "<p><strong>mārādā' wəbîšəttāʾ</strong> — 'rebellious and evil' (Aramaic mrd = to rebel, H4779). The letter characterizes Jerusalem twice with rebellion vocabulary before describing the building. <strong>šûrāyāʾ yəšaklilûn</strong> — 'they are finishing the walls' (Aramaic šāklal, H7955, to complete). The present-tense framing ('they are rebuilding … they are completing') makes the threat immediate rather than historical.</p>",
    "13": "<p><strong>mindāh bəlô wăhălāk</strong> — three tax terms: <em>mindāh</em> (tribute, H4061), <em>bəlô</em> (toll, H1093), <em>hălāk</em> (customs/duty, H1983). All three are Persian taxation categories; their enumeration in Aramaic mirrors actual Achaemenid administrative vocabulary known from other sources. The legal argument is purely economic: rebuilding Jerusalem = tax revenue loss. The letter weaponizes fiscal concerns.</p>",
    "14": "<p><strong>melaḥ hêkəlāʾ məliḥnāʾ</strong> — 'we eat the salt of the palace' (lit. 'we are salted with the salt of the palace'). Eating salt with someone creates a covenant of loyalty (cf. Ezra 6:9 where salt is part of offerings; Num 18:19 'covenant of salt'). To eat the king's salt and then be silent about threats to his honor would be covenant betrayal. The idiom explains the moral urgency of their report — loyalty demands disclosure.</p>",
    "15": "<p><strong>sēper dāḵrânāyāʾ</strong> — 'the record books' (Aramaic; <em>dāḵrôn</em>, H1799, memorial record/chronicle). The request to search the archives is historically realistic: Persian imperial archives were extensive and systematically organized. The claim that Jerusalem 'has long been rebellious' is a distortion of history framed as a search for precedent — using the empire's own administrative memory against the building project.</p>",
    "16": "<p><strong>ḥălāq lāʾ yihweh lāk</strong> — 'you will have no portion (<em>ḥălāq</em>) left in Trans-Euphrates.' The same covenant-allocation word from v3 now appears in the adversaries' letter — but weaponized: if Jerusalem is rebuilt, the king's territorial claim collapses. The irony is precise: the community that was told 'you have no portion' in the building now uses 'portion' language as a threat. The letter mirrors the rejection of v3.</p>",
    "17": "<p><strong>pəgam</strong> — 'reply/decree' (Aramaic, H6600; related to Persian <em>paiγāma</em>, message). The king's answer is formally sent back: <strong>šəlām wəkaʿet</strong> — 'peace, and now' is the standard Aramaic transition between greeting and substance in imperial correspondence. Artaxerxes' reply follows the exact counter-letter convention.</p>",
    "18": "<p><strong>pəraš miqrēʾ qoḏāmay</strong> — 'read aloud (<em>qərāʾ</em>) in full before me' (lit. 'translated and read before me'). <em>pəraš</em> (H6568, Aramaic; = Hebrew <em>pāraš</em>) means to make distinct/translate — suggesting the letter may have been translated from Aramaic into Persian for the king's personal reading. The king's response demonstrates he received and processed the full text, legitimizing the subsequent decree.</p>",
    "19": "<p><strong>šəliṭîn malkîn hāwôw bîrûšəlem</strong> — 'powerful kings have ruled in Jerusalem' — the archive search confirms the accusation. The Aramaic <em>šəliṭ</em> (H7990) = one having authority/power. The historical claim is accurate (David and Solomon's empires did extend to Trans-Euphrates), which makes the legal precedent usable. The search confirms the letter's accusation by its own logic.</p>",
    "20": "<p><strong>minkās, bəlô wǎhăḵāk</strong> — the same three-tax formula from v13 reappears in the king's reply, confirming he understood and accepted the fiscal framing. The parallel wording between the accusatory letter and the royal decree shows the accusers have successfully set the terms of the discussion: Jerusalem = fiscal threat = must be stopped.</p>",
    "21": "<p><strong>śîmû ṭəʿēm</strong> — 'issue a command' (lit. 'place a decree'). <em>ṭəʿēm</em> (H2942) recurs as the key word for royal decrees throughout Ezra (cf. 4:8; 5:3,9; 6:1,3,8,11,12; 7:13,21,23). The provisional character of the stop order is built into the text: 'until I give a further order' (<em>minněnî ṭəʿēm yitnəśēm</em>) — the suspension is temporary, leaving open the door for Darius's reversal in ch. 6.</p>",
    "22": "<p><strong>šālû lemeʿbaḏ pəšāʿ ḏənāh</strong> — 'be careful not to neglect this matter.' Aramaic <em>šəlī</em> (H7960) = negligence/error; <em>pəšāʿ</em> (H6588) = breach/transgression — the same root as Hebrew <em>pāšaʿ</em> (sin/rebellion). The rhetorical question 'Why should damage grow to hurt the king?' is a fiscal argument. The adversaries have successfully reframed a theological dispute (who may build the temple) as a purely political/economic threat.</p>",
    "23": "<p><strong>bəhipparaʿ</strong> — 'as soon as' (lit. 'in the uncovering/reading of'). The speed of the officials' response (they 'rushed' or 'hurried,' <em>ʾōḏaynāʾ</em>) demonstrates the leverage of an imperial letter. <strong>baʾdraʿ wəḥayil</strong> — 'by force and power' — Aramaic for armed compulsion. The rhetorical sequence: letter → decree → immediate armed enforcement. The adversaries achieve total legal and military victory. Temporally this is the nadir of the building narrative.</p>",
    "24": "<p><strong>bəṭēlat ʿăḇîḏat bêt-ʾĕlāhāʾ</strong> — 'the work of God's house in Jerusalem stopped.' Aramaic <em>bəṭēl</em> (H989) = to cease, be idle — the same root in the NT Greek <em>katargeō</em> (to make ineffective). <strong>ʿaḏ šənat tartên</strong> — 'until the second year of Darius.' The narrative resumes in ch. 5. The temple stoppage lasted approximately 16 years (ca. 534–520 BCE). The closing reference to Darius creates the narrative bridge to the next movement — a reversal is anticipated.</p>"
  },
  "5": {
    "1": "<p><strong>Aramaic continues (5:1–6:18).</strong> <strong>hitnaббî</strong> — hithpael of <em>nābāʾ</em> (H5013 Aramaic; = Hebrew H5012 nāḇāʾ), 'prophesied.' Haggai and Zechariah are named explicitly — their canonical books (Haggai and Zechariah 1–8) cover precisely this period (520–518 BCE). The prophetic word is the direct catalyst for resuming what the imperial letter had stopped. Divine speech overrides imperial decree. <strong>bəšum ʾĕlāh yiśrāʾēl</strong> — 'in the name of the God of Israel' — the divine authority grounding the resumption.</p>",
    "2": "<p><strong>qāmû</strong> — 'rose up' (Aramaic qûm, H6966); the prophetic word produces immediate action. <strong>yadaʾ ʾĕlāhāhôm ʿălêhôm</strong> — 'the hand of God was with them' (Aramaic <em>yaḏ</em>). 'The hand of God' (<em>yad ʾĕlōhîm</em>) is a standard Hebrew/Aramaic phrase for divine enablement — it recurs throughout Ezra in both languages (4:7; 7:6,9,28; 8:18,22,31). The prophets provide the word; the hand provides the power; the leaders provide the obedience.</p>",
    "3": "<p><strong>Tattenai</strong> — governor of Trans-Euphrates, attested in a cuneiform tablet from 502 BCE as 'Tattennu governor of Across-the-River' (Tattenai tablet, Oriental Institute), confirming the historicity of the name. <strong>man-śām lāḵôm ṭəʿēm</strong> — 'who issued you this decree?' (<em>ṭəʿēm</em> again, the operative word for official authorization). The challenge is procedural: the officials need to verify that the building has proper imperial authorization before allowing it.</p>",
    "4": "<p><strong>māh-šəmahaṯ gaḇrayyāʾ ḏî binyānāʾ ḏənāh bānyîn</strong> — 'what are the names of the men building this building?' The question is a census/registry request — standard administrative procedure for accountability. The Aramaic <em>gəḇar</em> (H1400) = man/person; <em>šəm</em> (H8036) = name. The names would be needed to make formal charges if the building was deemed unauthorized.</p>",
    "5": "<p><strong>ʿên ʾĕlāhāhôm</strong> — 'the eye of their God was upon the elders.' Aramaic <em>ʿayn</em> (H5870), identical to Hebrew <em>ʿayin</em>. The 'eye of the LORD' metaphor for divine protection and surveillance recurs throughout Scripture (Ps 34:15; 2 Chr 16:9). Its placement here is theologically precise: the eye of God suspends the normal consequence of the officials' challenge — they 'could not stop them' (lit. 'they did not make them stop') until Darius's word arrived. Divine watchfulness is the reason the building continues through the administrative delay.</p>",
    "6": "<p>The letter heading follows the same Aramaic epistolary convention as ch. 4. <strong>ʾăpārəsəkāyēʾ</strong> — the associates/inspectors; the same group as in 4:9,17. The letter is addressed 'to King Darius' rather than 'King Artaxerxes' — the narrative has moved chronologically back to Darius I (521–486 BCE), the Persian king who will ultimately authorize the building (ch. 6).</p>",
    "7": "<p><strong>šəlāmā kullāh</strong> — 'all/complete peace' (Aramaic <em>kōl šəlām</em>). Imperial Aramaic letters consistently open with this formulaic greeting. The inclusion of 'all' (<em>kōl/kullāh</em>) is a superlative intensifier — the greeting is perfunctory but follows proper form, signaling the letter is legitimate official correspondence, not a hostile accusation.</p>",
    "8": "<p><strong>lêbêt ʾĕlāhāʾ raḇbāʾ</strong> — 'the house of the great God.' The Persian governor Tattenai calls the Jerusalem temple the house of 'the great God' (<em>ʾĕlāh raḇ</em>) — the same adjective applied to Persian and Babylonian deities. This is not a confession of faith but an administrative reference; Persian religious policy was to acknowledge the gods of subject peoples. <strong>aḇnê gəlāl</strong> — 'dressed/hewn stone' (<em>gāll</em>, H1541 Aramaic, = rolling/large stones). The building description matches 6:4 specifications.</p>",
    "9": "<p><strong>šəʾêlnāʾ … man-śām lāḵôm ṭəʿēm</strong> — the same authorization question from v3 is now relayed verbatim in the letter. The repetition (<em>Wiederholung</em> technique) is characteristic of Hebrew/Aramaic prose — direct speech and reported speech match word-for-word, preserving the precision of the original exchange for the royal record.</p>",
    "10": "<p>Names are requested for the record — standard administrative accountability. The Aramaic infinitive <strong>ləhôḏāʿûtāḵ</strong> = 'to make known to you' (haphel of <em>ydaʿ</em>, H3046); the haphel is the Aramaic causative corresponding to Hebrew hiphil. The bureaucratic thoroughness of the Persian system is evident: names, authorization, and activity all need documenting before the king can adjudicate.</p>",
    "11": "<p><strong>ʾănaḥnâ himmô ʿaḇdôhî ḏî-ʾĕlāh šəmayyāʾ wʾarqāʾ</strong> — 'We are servants of the God of heaven and earth.' The elders' self-identification is theologically striking: they describe YHWH as 'God of heaven and earth' (<em>ʾĕlāh šəmayyāʾ wʾarqāʾ</em>) — the maximal title affirming universal sovereignty. This title echoes Gen 14:19 (El Elyon, creator of heaven and earth) and is used in Ezra precisely because it claims YHWH's jurisdiction exceeds any empire's. The historical claim that follows (Solomon built this house long ago) asserts prior right.</p>",
    "12": "<p><strong>ḥanăpū ʾăḇāhăṯānāʾ lêʾĕlāh šəmayyāʾ</strong> — 'our ancestors provoked the God of heaven to anger.' Aramaic <em>ḥanăp</em> (H2610) = to pollute/profane; the Aramaic root differs from the Hebrew <em>kāʿas</em> (provoke to anger) but achieves the same effect. The elders in their reply to Tattenai include a theological explanation of the exile — it was not divine weakness but divine judgment (<em>yəhab himmô bəyaḏ Nəḇûḵaḏneṣṣar</em>, 'he handed them over to Nebuchadnezzar'). The passive causative acknowledges YHWH's agency in the exile, which paradoxically strengthens their claim: the God who judged them is also the God now enabling the restoration.</p>",
    "13": "<p><strong>bišnaṯ ḥăḏāh</strong> — 'in the first year' (Aramaic ordinal construction). Cyrus of Babylon (= Cyrus II, who conquered Babylon in 539 BCE) issues the decree in his first year as king. The elders cite Cyrus's authorization as the legal basis for building. <strong>ṭəʿēm śām</strong> — 'issued a decree' — the same <em>ṭəʿēm</em> root that the adversaries challenged in v3 and v9; the elders now produce the authorizing <em>ṭəʿēm</em>.</p>",
    "14": "<p><strong>ʾăniyāʾ ḏîḏəhab wəḏî-ḵəsap</strong> — 'vessels of gold and silver.' The temple vessels are tracked from Nebuchadnezzar's looting (v14) through Cyrus's restoration order (v15) — their movement is a subplot of the entire Ezra narrative (cf. 1:7-11). The vessels function as material proof of covenant continuity: what was taken in judgment is returned in restoration. <em>Šəšbaṣṣar</em> (= Sheshbazzar) receives them as governor (<em>pəḥāh</em>, H6347).</p>",
    "15": "<p><strong>šqal ʾillēn ʾĕzal-yəhūb bəhêḵāl bîrûšlem</strong> — 'Take these and go, deposit them in the temple in Jerusalem.' The three Aramaic imperatives (<em>take, go, deposit</em>) express Cyrus's direct command. <strong>wəḇêṯ ʾĕlāhāʾ yitbənēʾ</strong> — 'let the house of God be rebuilt' — passive jussive, appropriate for an imperial authorization that creates permission rather than commanding personal action.</p>",
    "16": "<p><strong>yəhab ʾušśāʾ ḏî-bêt ʾĕlāhāʾ bîrûšlem</strong> — 'laid the foundation of God's house in Jerusalem.' Sheshbazzar laid the foundation under Cyrus; Zerubbabel (under Darius) resumed the superstructure. Two separate foundation-laying moments (Ezra 3:10 under Zerubbabel; here under Sheshbazzar) likely reflect two distinct phases of the early restoration. The phrase <strong>ʾūšşāʾ</strong> (Aramaic <em>ʾūššāʾ</em>, H787) = foundation/base; the foundation is the theological symbol of covenant recommitment.</p>",
    "17": "<p><strong>wəkhət yiṭṭab ʿal-malkāʾ</strong> — 'if it pleases the king' (lit. 'if it is good upon the king') — standard Aramaic petition formula for requesting a royal search. The elders' strategy is brilliant: rather than demanding rights, they request a search of the king's own archives. The Persians prided themselves on accurate record-keeping; appealing to the archives shifts the burden of proof to the imperial record itself. <strong>dāḵrônāyāʾ</strong> (H1799 = records/chronicles) recurs from 4:15 — the same archives the adversaries cited are now invoked to vindicate the builders.</p>"
  },
  "6": {
    "1": "<p><strong>Aramaic continues (6:1–18).</strong> <strong>śām ṭəʿēm Dāryāwēš</strong> — 'King Darius issued a decree' (lit. 'placed a ṭəʿēm'). The verb <em>śîm ṭəʿēm</em> has appeared repeatedly (4:21; 5:3,9,13); now it is Darius himself placing the operative decree. <strong>bêt sifrayyāʾ</strong> — 'the house of archives/records.' Persian records were kept at multiple royal residences; Darius orders a search of the Babylonian archives, separate from the Ecbatana archives where the scroll is found.</p>",
    "2": "<p><strong>ʾAḥməṯāʾ</strong> — Ecbatana (modern Hamadan, Iran), the Median summer capital of the Achaemenid kings. The scroll is found there — not in Babylon where the search was ordered — which is historically plausible; Cyrus spent considerable time in Media after conquering Babylon. <strong>megillāh</strong> — 'scroll' (Aramaic; = Hebrew <em>məgillāh</em>, H4040). The same word for the scroll of Esther (megillat Esther). The Cyrus decree exists on an actual archival scroll, not just in memory.</p>",
    "3": "<p><strong>šənaṯ ḥăḏāh</strong> — 'first year of Cyrus' (538/7 BCE). The decree itself is now quoted directly: <strong>bêṯ ʾĕlāhāʾ yitbənēʾ</strong> — 'let the house of God be built.' The building specifications — 'height 60 cubits, width 60 cubits' — are given in Aramaic cubit measurements. These are substantially larger than the second temple actually became (Herod's later enlargement reached this scale), suggesting either the decree was programmatic rather than prescriptive, or a textual variant in numbers.</p>",
    "4": "<p><strong>nidbāḵîn di-ʾeḇen gəlāl</strong> — 'courses of large dressed stone.' <em>Nidbāḵ</em> (Aramaic, H5073) = a course or layer of stones in construction. Three stone courses alternating with one timber course was standard ANE mudbrick/stone hybrid construction (cf. 1 Kgs 6:36; 7:12 for Solomon's temple using the same technique). <strong>min-bêṯ malkāʾ yittyəhēb</strong> — 'from the royal treasury shall it be paid' — the Persian crown underwrites the rebuilding. Persian royal patronage of foreign temples is confirmed by the Cyrus Cylinder.</p>",
    "5": "<p><strong>ʾănayyāʾ ḏî-ḏahabāʾ wəḵəsāp</strong> — 'the gold and silver vessels.' The vessels are named again (cf. 5:14-15); their restoration to Jerusalem is a central act of the Cyrus decree. <strong>taḵtāhôn</strong> — 'in their place' (lit. 'under them'); the Aramaic preposition <em>taḥat</em> (H8460) = under/in place of. The vessels must be returned to their original location — the language of precise restoration rather than generic return.</p>",
    "6": "<p><strong>kəʿat</strong> — 'now/therefore' (Aramaic; transitional from the citation of Cyrus's decree to Darius's own decree). Darius addresses Tattenai directly: <strong>rəḥîqîn hěwô min-tammāh</strong> — 'keep away from there' (lit. 'be distant from that place'). The command reverses ch. 4's enforcement: what the adversaries had stopped, the king's decree now protects. The same imperial authority that was weaponized against building is now weaponized for building.</p>",
    "7": "<p><strong>šəḇûqû laʿăḇîḏaṯ bêṯ-ʾĕlāhāʾ ḏēn</strong> — 'leave alone the work of this house of God.' Aramaic <em>šəḇaq</em> (H7662) = to leave/permit/allow. The same root appears in the Lord's Prayer (Aramaic <em>šəḇaq</em> = 'forgive/release'). <strong>pəḥaṯ yəhûḏāyēʾ</strong> — 'the governor of the Jews' — authority is delegated to the local Jewish governor (Zerubbabel) and elders; Persian oversight withdraws. The verb construction is imperatival: Darius commands Tattenai's non-interference.</p>",
    "8": "<p><strong>miḏatṯ ʾăḵəsfarnāyāʾ</strong> — 'from the royal revenues' (<em>miḏāh</em>, H4061, is the tribute/tax term from 4:13). The reverse of the adversaries' argument: they warned that Jerusalem's rebuilding would reduce tax revenue; now Darius orders that tax revenue fund the rebuilding. The fiscal argument is flipped. <strong>ḇə-ʾosparnāʾ</strong> — 'diligently, without delay' (H629); the same adverb appears in 5:8 and 7:17,21,26 — a key Aramaic administrative term for urgent, proper execution of orders.</p>",
    "9": "<p><strong>ʿănê ṯôrîn</strong> — 'young bulls' (Aramaic <em>ʿanê</em>, H6450). The list of sacrificial materials — bulls, rams, lambs, wheat, salt, wine, oil — mirrors Levitical requirements (Lev 1–7). That Darius specifies exact sacrificial requirements reflects Persian religious policy: to supply the needs of subject-peoples' temples in exchange for prayers for the imperial household. <strong>millāḥ</strong> — salt (H4416); salt is both a preservative and a covenant marker (Lev 2:13; Num 18:19; cf. Ezra 4:14 'we eat the king's salt').</p>",
    "10": "<p><strong>liqrāḇāh nîḥôḥîn</strong> — 'to offer acceptable sacrifices' (lit. 'to offer pleasing-aroma sacrifices'). Aramaic <em>nîḥôaḥ</em> (H5208) = pleasant aroma — the Aramaic form of Hebrew <em>nîḥôaḥ</em> (H5207), the same word used throughout Leviticus for offerings acceptable to YHWH (Lev 1:9,13,17 etc.). The pagan king uses the technical sacrificial vocabulary. <strong>wəyitṣallôn</strong> — 'and pray' (Aramaic pael of ṣlh, H6739); the exchange is explicit: Persian money → Jewish sacrifices and prayers → divine protection of Persia. Pragmatic polytheism from the Persian side; genuine worship from the Jewish side.</p>",
    "11": "<p><strong>ʾîlān mêbiṯēh</strong> — 'a beam pulled from his house' — the death penalty is expressed in construction language (a beam <em>pulled from</em> his house), then the offender is 'impaled on it' (<em>məmḥēʾ ʿălôhî</em>). This is the standard Persian royal decree formula for capital offenses, attested in other Achaemenid inscriptions. <strong>ûnְwālî yitʿəḇad</strong> — 'and his house made a dunghill/ruin.' The complete reversal: from house-owner to impaled-on-his-own-beam, house to dunghill. The severity underscores that Darius's protection of the temple is binding, not optional.</p>",
    "12": "<p><strong>wêʾĕlāhāʾ ḏî-šakkan šəmēh tamāh</strong> — 'the God who caused his name to dwell there.' This is the most theologically significant verse in the Aramaic section. <em>Šakkan šəmēh</em> is the Aramaic exact equivalent of the Deuteronomic formula <em>šikkēn šəmô</em> (Deut 12:5,11; 14:23; 16:2,6,11; 26:2) — the theology of divine name-presence in the sanctuary. That this Deuteronomic formula appears in an Aramaic imperial decree attributed to Darius is remarkable: either Darius's scribes adapted Jewish theological language, or the text was edited by the Chronicler to embed the name-theology. Either way, the Chronicler places YHWH's name-presence at the center of his decree — the temple is the place where YHWH's name dwells, and any king who interferes with it opposes YHWH himself.</p>",
    "13": "<p><strong>ʾōsparnāʾ</strong> — 'diligently/exactly' (H629, same as v8). Tattenai's compliance is described with the same adverb that Darius used for his command — word-for-word obedience. The narrative signals that imperial opposition to the covenant community has completely reversed: the same officials who threatened to stop the building (4:23–24) now fully comply with its protection. <strong>kəmāʾ ḏî śām Dāryāwēš</strong> — 'exactly as Darius had decreed' — the verbal echo closes the loop.</p>",
    "14": "<p><strong>wūbənô … wəṣliḥû bənăḇûʾaṯ ḥaggay</strong> — 'they built and prospered through the prophecy of Haggai.' Three Aramaic verbs in sequence: <em>bənô</em> (built), <em>ṣliḥû</em> (prospered/succeeded), <em>šaklilû</em> (finished). The middle verb <em>ṣlāḥ</em> (H6744) = to prosper, succeed — it is YHWH's blessing on the activity, not just human effort. <strong>bəmiṣwaṯ ʾĕlāh-yiśrāʾēl ûmiṭṭəʿēm Kôreš ûDāryāwēš</strong> — 'by the command of the God of Israel and the decree of Cyrus, Darius, and Artaxerxes.' The Chronicler deliberately merges divine command and imperial decree: three Persian kings and the one God of Israel all concur in the building.</p>",
    "15": "<p><strong>wayyiḵlēʾ bêṯāʾ</strong> — 'the house was completed' (Aramaic <em>klāʾ</em>, H3635 = to complete). The date: third day of Adar, sixth year of Darius = March 12, 516 BCE. The significance of this date is striking: if the temple was destroyed in 586 BCE (2 Kgs 25:8–9), the second temple's completion in 516 BCE falls exactly 70 years later — the duration of Jeremiah's predicted desolation (Jer 25:11–12; 29:10; cf. Zech 1:12; Dan 9:2). The 70-year structure is not incidental; the Chronicler (and Darius's decree by implication) positions the temple completion as the fulfillment of Jeremiah's prophecy.</p>",
    "16": "<p><strong>Hebrew resumes at 6:16.</strong> <strong>ḥănukkāh</strong> — 'dedication' (H2598 ḥăṇukkāh; same word as the later Hanukkah festival, itself a second-temple dedication celebration). <strong>bənê-yiśrāʾēl</strong> — 'sons of Israel' — the covenant-community name deliberately recalls the exodus narrative. The dedication is celebrated with joy (<em>bəśimḥāh</em>). The return from exile is implicitly a new exodus; the temple dedication recapitulates Sinai-era consecration.</p>",
    "17": "<p><strong>ḥaṭṭāʾt ləḵol-yiśrāʾēl šənêm-ʿāśār śəʿîrê ʿizzîm</strong> — 'twelve male goats as a sin offering for all Israel' — twelve goats for the twelve tribes. That only returned exiles (principally Judah and Benjamin, with some Levites) perform this offering on behalf of 'all Israel' is a theological claim: the restoration community stands as the representative of the whole covenant people. The twelve-tribe symbolism had been claimed at Zerubbabel's altar (3:1–2); it is now reiterated in the temple dedication.</p>",
    "18": "<p><strong>wayaʿămiḏû</strong> — 'they appointed/stationed' (hiphil of <em>ʿāmaḏ</em>, H5975). The priestly and Levitical divisions are established <strong>kəḵeṯaḇ sēper Mōšeh</strong> — 'as written in the book of Moses.' The explicit appeal to the Mosaic text grounds the restored worship in Torah. The Chronicler consistently emphasizes that authentic worship requires Mosaic authorization (cf. 2 Chr 35:26). The institutional structure of the temple (divisions, courses, orders) is the embodiment of covenantal order.</p>",
    "19": "<p><strong>wayyaʿăśû ḇənê-haggôlāh ʾeṯ-happāsaḥ</strong> — 'the returned exiles observed the Passover.' The Passover (<em>pāsaḥ</em>, H6453) is the covenant-renewal meal par excellence — it marks the founding of Israel as a redeemed community (Exod 12). Its observance here signals that the exile is formally over: the community stands in the same position as the exodus generation, re-constituted as YHWH's people in the land. The Passover connects the restored community to the original deliverance.</p>",
    "20": "<p><strong>kî ṭihărû yāḥaḏ</strong> — 'for they had all purified themselves together.' The ritual purity is thorough and corporate (<em>yāḥaḏ</em>). Priestly purity enabled them to slaughter the Passover lamb 'for all the returned exiles' — the priests served the whole community. The hiphil verb <em>šəḥāṭû</em> (slaughtered) indicates the priests performing the sacrifice on behalf of laity, a Second Temple innovation from the norm of family-slaughter in Exod 12.</p>",
    "21": "<p><strong>niḇdəlû meṭumʾat gôyê hāʾāreṣ</strong> — 'who had separated themselves from the impurity of the nations of the land.' The phrase is significant: the Passover includes not only the returned exiles but also those who 'joined them' by separating from syncretistic practice. This is an inclusionary provision — non-exilic Israelites (who had remained in the land) could participate in the covenant community by ritual separation from pagan contamination. The theological principle: covenant membership is defined by commitment to YHWH, not only by exile-and-return history.</p>",
    "22": "<p><strong>wayyəśabbēr YHWH ʾet-libbam meleḵ ʾaššûr</strong> — 'the LORD turned the heart of the king of Assyria toward them.' The king is called 'king of Assyria' though he is Darius/Artaxerxes — the Chronicler uses 'Assyria' as a symbolic name for the dominant gentile power (as in Neh 9:32). <strong>hāsēb ʾeṯ-libbô</strong> — lit. 'turned his heart' — the same verb and idiom as 2 Chr 36:22 (Cyrus's heart 'stirred' by YHWH) and Prov 21:1 ('the king's heart is in YHWH's hand'). The confession that closes the dedication narrative: the imperial authorization was divinely orchestrated.</p>"
  },
  "7": {
    "1": "<p><strong>Hebrew resumes (7:1).</strong> <strong>ʾaḥar hadəḇārîm hāʾēlleh</strong> — 'after these events/things.' The standard narrative transition formula signals a major chronological gap: Ezra 6 ends in 516 BCE; Ezra 7 begins in 458 BCE — a 57-year silence in the text. The narrative bridge is intentional: the Chronicler moves from temple completion (the first restoration) to Torah re-establishment (the second restoration under Ezra). <strong>bəmalkûṯ ʾArtaḥšaśtāʾ</strong> — Artaxerxes I (465–424 BCE).</p>",
    "2": "<p>Ezra's genealogy: <strong>ben-Śərāyāh ben-ʿAzaryāh ben-Ḥilqiyyāh</strong> — the ancestry traces from Ezra through Seraiah (the chief priest killed at Jerusalem's fall, 2 Kgs 25:18–21) backward toward Aaron. The genealogy is selective — 16 names for roughly 1,000 years from Aaron to Ezra — compressing generations as Matthew's genealogy does. The key link is the Zadokite/Aaronide lineage establishing Ezra's priestly credentials.</p>",
    "3": "<p>Continuation of the genealogical chain. <strong>ben-Zeraḥyāh ben-ʿUzzî ben-Buqqî</strong> — these names correspond to priests listed in 1 Chr 6:5–15. The Chronicler's genealogical data is consistent across books, suggesting use of temple archival records. The chain passes through Phinehas (v5), who received the covenant of perpetual priesthood (Num 25:13) — another anticipation of covenant faithfulness.</p>",
    "4": "<p>The genealogy continues through the priestly line. The listing of priests' ancestors serves the same function as royal genealogies: establishing legitimacy for office. Ezra's authority to teach Torah and lead reform rests on this Aaronide lineage — it is not merely personal merit but covenantal appointment by descent.</p>",
    "5": "<p><strong>ben-Pîneḥās ben-ʾElʿāzār ben-ʾAhărôn hakkōhēn hārōʾš</strong> — 'son of Phinehas, son of Eleazar, son of Aaron the chief priest.' The genealogy terminates at Aaron, the first high priest. Phinehas received the covenant of a perpetual priesthood (Num 25:12–13) because of his zeal for YHWH's honor. Ezra inherits both the Aaronide office and, implicitly, the Phinehite zeal that will characterize his reform activities (Ezra 9–10).</p>",
    "6": "<p><strong>sōpēr māhîr bəṯôrat Mōšeh</strong> — 'skilled scribe in the law of Moses.' <em>Sōpēr</em> (H5608) is the professional scribal class; <em>māhîr</em> (H4106) = swift, skilled, expert (cf. Ps 45:1 'my tongue is the pen of a <em>sōpēr māhîr</em>,' a skilled writer). Ezra's qualification is twofold: scribal craft (the ability to read, copy, and interpret texts) and the specific subject (the law of Moses). The combination defines the new post-exilic leader type: not king or prophet but Torah-scholar. <strong>yad-YHWH ʾĕlōhāyw ʿālāyw</strong> — 'the good hand of the LORD his God was upon him' — first occurrence of the recurring <em>yad ṭôbāh</em> formula (vv9,28; Neh 2:8,18).</p>",
    "7": "<p><strong>ûmibənê yiśrāʾēl ûmin-hakkōhănîm</strong> — 'some of the Israelites, including priests, Levites, singers, gatekeepers, and Nethinim.' The Nethinim (<em>nəṯînîm</em>, H5411 = temple servants, 'given ones') were temple assistants, possibly descendants of non-Israelites who had joined the temple service (cf. Josh 9:27 Gibeonites). Their inclusion shows the breadth of the return: it was not only Judahites but the full temple-service community.</p>",
    "8": "<p><strong>bah-ḥōdeš haḥămiššî</strong> — 'in the fifth month.' The journey from Babylon to Jerusalem: first month of departure (7:9), fifth month of arrival. The travel time (~4 months) matches the caravan distance (Babylon to Jerusalem ~900 miles). The dating to the 'seventh year of Artaxerxes' = 458 BCE if Artaxerxes I, or 398 BCE if Artaxerxes II (the date is debated; the 458 BCE reading is dominant).</p>",
    "9": "<p><strong>kî bəʾeḥāḏ laḥōdeš hārîʾšôn</strong> — 'on the first day of the first month.' The departure on the first of Nisan is theologically charged: Nisan is the month of Passover (Exod 12:2 'this month shall be the beginning of months for you'). Ezra's departure begins on New Year's Day of the sacred calendar. <strong>yad ʾĕlōhāyw haṭṭôḇāh ʿālāyw</strong> — 'the good hand of his God upon him' — the formula (second occurrence) explains the successful journey: not skill but divine providence.</p>",
    "10": "<p><strong>kî ʿEzrāʾ hēkîn liḇbô liḏrôš ʾeṯ-Tôrat YHWH wəlaʿăśôṯ wûllammeḏ bəyiśrāʾēl ḥōq ûmišpāṭ</strong> — 'For Ezra had devoted his heart to study the law of the LORD, to practice it, and to teach statute and ordinance in Israel.' This verse is the theological charter for the scribal vocation. The three verbs: <em>dāraš</em> (H1875 = seek/study), <em>ʿāśāh</em> (H6213 = do/practice), <em>lāmaḏ</em> (H3925 = teach). The order is not accidental: study precedes practice, practice precedes teaching. One cannot authentically teach what one has not first practiced; one cannot practice what one has not first studied. <em>Hēkîn liḇbô</em> — 'prepared/set his heart' — the hiphil of <em>kûn</em> + <em>lēḇ</em>: the heart as the organ of intentional commitment. The Talmud (b. Qiddushin 40b) quotes this verse as the paradigm for the proper order of learning and doing.</p>",
    "11": "<p><strong>ništevan hakkiṯāḇ ʾăšer nātan hammelek</strong> — 'this is the copy of the letter that the king gave.' <em>Ništevan</em> (H5406) is a Persian loanword (<em>nipishtāpana</em> = dispatch/written order). Its occurrence here signals the switch back to Aramaic in vv12–26, where Artaxerxes' actual letter is embedded. The letter is described as 'the text' (<em>nušḥāh</em>) — an official copy for the record.</p>",
    "12": "<p><strong>Aramaic section begins (7:12–26).</strong> <strong>Artaḥšaśtāʾ meleḵ malkayāʾ</strong> — 'Artaxerxes, king of kings.' The royal title <em>meleḵ malkayāʾ</em> (king of kings) is the standard Achaemenid superlative title, attested in Persian royal inscriptions (Darius: 'I am Darius the great king, king of kings'). The same title is applied to YHWH in 1 Tim 6:15 and to Christ in Rev 17:14; 19:16 — the NT appropriates the highest imperial title for the one true King. <strong>šəlām lāʿeṯ ûkəʿeṯ</strong> — 'peace in full, and now' — the Aramaic greeting formula before the substantive decree.</p>",
    "13": "<p><strong>min-qoḏāmay śîm ṭəʿēm</strong> — 'I hereby decree' (lit. 'from before me a decree is placed'). The impersonal passive construction is typical of official Aramaic decrees — the decree takes on a semi-autonomous legal force, not just personal expression. <strong>kol-miṯnaddəḇ</strong> — 'whoever volunteers willingly' (Aramaic hitpael of <em>ndḇ</em>, H5068; cf. Hebrew <em>nāḏaḇ</em>, freewill offering). The departure is voluntary — the letter is not conscription but an invitation.</p>",
    "14": "<p><strong>min-qoḏam malkāʾ</strong> — 'from before the king' — 'sent by the king and his seven counselors.' The seven counselors are historically attested: Esther 1:14 mentions the seven princes of Persia and Media; Herodotus (III.84) confirms a council of seven nobles in the Achaemenid court. <strong>kəḏāṯ ʾĕlāhāḵ</strong> — 'in accordance with the law of your God' — the decree explicitly validates Torah as the governing law within the Jewish community. The Persian crown delegates legal authority to divine law.</p>",
    "15": "<p><strong>ûlhêṯāyāh kesef ûḏəhaḇ</strong> — 'to carry the silver and gold.' The freewill gifts recall the Exodus pattern (Exod 12:35–36, Israel 'spoiled' Egypt of silver and gold; Exod 36:3–7, freewill offerings for the tabernacle). The return from Babylonian exile reproduces the exodus-to-tabernacle movement: departure, gifts of precious metals, construction/dedication of a worship site. The vocabulary of <em>mitnaddəḇ</em> (v13) and <em>nəḏābāh</em> (freewill offering) recurs throughout the tabernacle account (Exod 25:2; 35:5,21,29).</p>",
    "16": "<p><strong>kol-kesef ûḏəhaḇ ḏî-tiškaḥ</strong> — 'all the silver and gold you can gather/find.' The Aramaic <em>šəkaḥ</em> (H7912) = to find/gather; the same root in Ezra 5:17 (search the archives). The gathering of resources from the province of Babylon parallels the tabernacle-construction offering: voluntary contributions from the whole community. The parenthetical phrase 'freewill gifts of the people and priests' reinforces the voluntary, covenantal character of the giving.</p>",
    "17": "<p><strong>bəʾosparnāʾ</strong> — 'diligently' (H629 = same adverb as 6:8,12,13). The word recurs to bind Artaxerxes' decree to Darius's — both kings require prompt, exact compliance. The animals listed for sacrifice (bulls, rams, lambs) mirror the Passover and dedication offering lists of ch. 6 — the restored community's sacrificial calendar is being re-established with imperial funding.</p>",
    "18": "<p><strong>ûḏî-ʿălāḵ wəʿal-ʾaḥāyāḵ yîṭab</strong> — 'whatever you and your fellow countrymen decide is fitting.' The decree grants Ezra discretionary authority over the remainder of the silver and gold 'according to the will of your God' (<em>kəreʿûṯ ʾĕlāhăḵôn</em>). This is remarkable: the Persian king explicitly defers to divine will in the management of the funds. The Achaemenid policy of religious patronage reaches its maximum expression here.</p>",
    "19": "<p><strong>wəʾănayyāʾ ḏî-miṯyəhiḇîn lāḵ</strong> — 'the vessels given to you.' The vessels are 'given' (<em>yəhab</em>, haphel passive) for the 'service of the house of your God' (<em>pûlḥān bêt ʾĕlāhāḵ</em>). <em>Pûlḥān</em> (H6399) = worship/service — the Aramaic term for temple liturgical service, cognate with Hebrew <em>pālaḥ</em>. The vessels are not property but sacred implements assigned to specific liturgical use.</p>",
    "20": "<p><strong>min-bêt ginzê malkāʾ</strong> — 'from the royal treasury' (<em>ginzê</em>, H1596, from Persian <em>ganj</em> = treasury/storehouse). The treasury is available for any additional needs of the temple service. The phrase 'that you find occasion to supply' (<em>ʾăšer yippal ʿălāyk</em>, lit. 'that falls upon you') is an open-ended authorization — Ezra has blank-check authority for temple necessities, within reason.</p>",
    "21": "<p><strong>ûminnenî ʾănaʾ Artaḥšaśtāʾ malkāʾ</strong> — 'I, King Artaxerxes, hereby order.' The first-person emphatic pronoun (<em>ʾănaʾ</em>) is unusual in imperial decrees — it personalizes the king's commitment. The treasurers of Trans-Euphrates are commanded directly, removing any bureaucratic intermediaries between Ezra's requests and royal fulfillment. The scope is deliberately large: all treasurers in the entire western satrapy must comply.</p>",
    "22": "<p>The enumerated limits — 100 talents of silver, 100 measures of wheat, 100 baths of wine, 100 baths of oil, and unlimited salt — are substantial but not unlimited. The 100-unit pattern may be a formulaic round number (a common administrative convention) rather than a precise budget. The addition 'and salt without limit' (<em>ûmalaḥ ḏî-lāʾ kəṯāḇ</em>) is notable: salt had covenant significance (cf. 4:14 'we eat the king's salt') and was essential for all sacrificial offerings (Lev 2:13).</p>",
    "23": "<p><strong>kol-ḏî min-ṭəʿēm ʾĕlāh šəmayyāʾ</strong> — 'whatever the God of heaven commands.' The decree subordinates Persian imperial authority to YHWH's commands: 'carry it out faithfully for his house.' <strong>ûlmāh yihwēʾ qəṣap</strong> — 'for why should wrath come upon the kingdom?' The motivation is apotropaic: Persian support for the temple averts divine wrath from the empire. The theology is fully Ezra's (YHWH governs history), expressed in the pagan king's pragmatic terms. The same logic underlies Cyrus's decree (1:2–4) and Darius's (6:10).</p>",
    "24": "<p><strong>wûlāḵôn məhôḏaʿîn</strong> — 'and we also declare.' The tax exemption for temple personnel — priests, Levites, singers, gatekeepers, Nethinim, and temple servants — is legally binding: 'it is not lawful (<em>šallîṭ</em> lāʾ) to impose tribute, tax, or duty on them.' This exemption protected the economic viability of the temple service; without it, the financial burden on temple workers would have made sustained temple service impossible.</p>",
    "25": "<p><strong>wəʾantāh ʿEzrāʾ kiḥoḵmaṯ ʾĕlāhāḵ ḏî-beyadāḵ</strong> — 'And you, Ezra, using the wisdom of your God that you possess.' The delegation of judicial authority to Ezra is based on <em>ḥoḵmaṯ ʾĕlāhāḵ</em> — 'the wisdom of your God' — not just bureaucratic appointment. <strong>manne śāpəṭîn wəḏayyānîn</strong> — 'appoint judges and magistrates.' Ezra receives authority to establish courts for all Jews in Trans-Euphrates who know the Torah laws. The implicit standard: <em>dāṯ ʾĕlāhāḵ</em> (law of your God) and <em>dāṯ malkāʾ</em> (law of the king) are placed in explicit parallel — Torah and imperial law cooperate.</p>",
    "26": "<p><strong>wəḵol-ḏî lāʾ lehěwēʾ ʿāḇēḏ dāṯ ʾĕlāhāḵ</strong> — 'anyone who refuses to obey the law of your God.' The penalties — death, exile, confiscation, imprisonment — are the standard four punishments of Achaemenid criminal law (attested in Persian legal texts). Notably, violating God's law and the king's law carry the same legal consequences. The imperial decree enforces Torah compliance with the full weight of Persian penal authority. This is the furthest extent of the 'law of God and law of king' convergence in the Achaemenid period.</p>",
    "27": "<p><strong>Bārûḵ YHWH ʾĕlōhê ʾăḇōṯênû</strong> — 'Blessed be the LORD, the God of our ancestors.' The Hebrew resumes; Ezra breaks into spontaneous doxology. This is one of the rare first-person passages in Ezra (9:1–15 is the other), shifting from third-person narrative to Ezra's own voice. The blessing formula (<em>bārûḵ</em>) is the standard Hebrew doxology (cf. Gen 24:27; 1 Sam 25:32; 2 Sam 18:28; Ps 28:6; 31:21). <strong>ʾăšer nātan kāzōʾt bəlēb hammelek</strong> — 'who put such a thing as this in the king's heart' — <em>nātan bəlēb</em> (put in heart) is the idiom for divine inspiration of human decision (Neh 2:12; 7:5; Prov 21:1). YHWH's sovereignty over the Persian king's heart is the theological climax of the chapter.</p>",
    "28": "<p><strong>wəʿālay hiṭṭāh ḥeseḏ</strong> — 'He has shown me steadfast love' (<em>ḥeseḏ</em>, H2617 = covenant faithfulness, steadfast love). <em>Ḥeseḏ</em> is the covenant-loyalty word par excellence — it encompasses faithfulness, mercy, and sustained commitment. That Ezra attributes the king's favor to YHWH's <em>ḥeseḏ</em> toward him personally is both personal testimony and theological interpretation: the imperial decree is YHWH's covenantal provision. <strong>waʾăḥazzēq ḵəyad YHWH ʾĕlōhay ʿālay</strong> — 'I strengthened myself as the good hand of the LORD my God was upon me' — the third occurrence of the <em>yad</em> formula (vv6,9,28), framing the entire chapter with divine enablement. Ezra's strength is derivative; the hand of YHWH is the true agent.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'ezra')
    merge_comm(c, EZRA)
    save_comm('mkt-original', 'ezra', c)
    count = sum(len(v) for v in EZRA.values())
    print(f'ezra mkt-original: wrote {count} verses for ch 4-7')

if __name__ == '__main__':
    main()
